bt('Django\u662f\u4e00\u4e2a\u9ad8\u7ea7Python Web\u6846\u67b6\uff0c\u91c7\u7528MTV\uff08Model-Template-View\uff09\u67b6\u6784\u6a21\u5f0f\u3002\u5b83\u9075\u5faa\u201c\u7535\u6c60\u5305\u542b\u201d\uff08batteries-included\uff09\u7684\u8bbe\u8ba1\u54f2\u5b66\uff0c\u5185\u7f6e\u4e86ORM\u3001\u8ba4\u8bc1\u7cfb\u7edf\u3001\u7ba1\u7406\u540e\u53f0\u3001\u8868\u5355\u5904\u7406\u7b49\u4e30\u5bcc\u7684\u529f\u80fd\u6a21\u5757\u3002Django\u5f3a\u5927\u7684ORM\u652f\u6301\u591a\u79cd\u6570\u636e\u5e93\u540e\u7aef\uff0c\u5f00\u53d1\u8005\u65e0\u9700\u76f4\u63a5\u7f16\u5199SQL\u8bed\u53e5\u5373\u53ef\u5b8c\u6210\u6570\u636e\u5e93\u64cd\u4f5c\u3002\u5728\u672c\u9879\u76ee\u4e2d\uff0cDjango 6.0\u4f5c\u4e3a\u540e\u7aef\u6846\u67b6\uff0c\u8d1f\u8d23\u63d0\u4f9bRESTful API\u63a5\u53e3\u3001\u6570\u636e\u6301\u4e45\u5316\u5b58\u50a8\u548c\u7ba1\u7406\u540e\u53f0\u3002')

doc.add_heading('2.3 Vite\u6784\u5efa\u5de5\u5177', level=2)
bt('Vite\u662f\u65b0\u4e00\u4ee3\u524d\u7aef\u6784\u5efa\u5de5\u5177\uff0c\u7531Vue.js\u4f5c\u8005\u5c24\u96e8\u6eaa\u5f00\u53d1\u3002\u76f8\u6bd4\u4f20\u7edf\u7684Webpack\u7b49\u6253\u5305\u5de5\u5177\uff0cVite\u5728\u5f00\u53d1\u6a21\u5f0f\u4e0b\u5229\u7528\u6d4f\u89c8\u5668\u539f\u751fES\u6a21\u5757\uff0c\u5b9e\u73b0\u4e86\u6781\u901f\u7684\u51b7\u542f\u52a8\u548c\u70ed\u66f4\u65b0\u3002\u5728\u751f\u4ea7\u6784\u5efa\u65f6\uff0cVite\u4f7f\u7528Rollup\u8fdb\u884c\u6253\u5305\uff0c\u63d0\u4f9b\u4e86\u9ad8\u6548\u7684\u4ee3\u7801\u5206\u5272\u548c\u8d44\u6e90\u4f18\u5316\u3002\u672c\u9879\u76ee\u4e2dVite 6\u4f5c\u4e3a\u6784\u5efa\u5de5\u5177\uff0c\u914d\u5408@vitejs/plugin-react\u63d2\u4ef6\uff0c\u4e3aReact\u5f00\u53d1\u63d0\u4f9b\u4e86\u6d41\u7545\u7684\u5f00\u53d1\u4f53\u9a8c\u3002')

doc.add_heading('2.4 GSAP\u52a8\u753b\u6280\u672f', level=2)
bt('GSAP\uff08GreenSock Animation Platform\uff09\u662f\u4e00\u4e2a\u529f\u80fd\u5f3a\u5927\u7684JavaScript\u52a8\u753b\u5e93\uff0c\u88ab\u5e7f\u6cdb\u7528\u4e8e\u521b\u5efa\u9ad8\u6027\u80fd\u7684Web\u52a8\u753b\u3002GSAP\u63d0\u4f9b\u4e86\u4e30\u5bcc\u7684API\uff0c\u5305\u62ec\u8865\u95f4\u52a8\u753b\uff08tween\uff09\u3001\u65f6\u95f4\u7ebf\uff08timeline\uff09\u3001\u6eda\u52a8\u89e6\u53d1\u5668\uff08ScrollTrigger\uff09\u7b49\u3002\u5176\u6838\u5fc3\u4f18\u52bf\u5728\u4e8e\u8de8\u6d4f\u89c8\u5668\u517c\u5bb9\u6027\u597d\u3001\u6027\u80fd\u4f18\u5f02\u3001\u52a8\u753b\u63a7\u5236\u7cbe\u786e\u3002\u5728\u672c\u9879\u76ee\u4e2d\uff0cGSAP\u4e0eScrollTrigger\u63d2\u4ef6\u914d\u5408\u4f7f\u7528\uff0c\u5b9e\u73b0\u4e86\u9875\u9762\u6eda\u52a8\u9a71\u52a8\u7684\u5165\u573a\u52a8\u753b\u3001\u89c6\u5dee\u6548\u679c\u548c\u5143\u7d20\u8fc7\u6e21\u52a8\u753b\uff0c\u663e\u8457\u63d0\u5347\u4e86\u7528\u6237\u4f53\u9a8c\u3002')

doc.add_heading('2.5 SQLite\u6570\u636e\u5e93', level=2)
bt('SQLite\u662f\u4e00\u4e2a\u8f7b\u91cf\u7ea7\u7684\u5173\u7cfb\u578b\u6570\u636e\u5e93\u5f15\u64ce\uff0c\u4ee5\u5d4c\u5165\u5f0f\u65b9\u5f0f\u8fd0\u884c\uff0c\u65e0\u9700\u72ec\u7acb\u7684\u6570\u636e\u5e93\u670d\u52a1\u5668\u3002SQLite\u5c06\u6574\u4e2a\u6570\u636e\u5e93\u5b58\u50a8\u5728\u4e00\u4e2a\u5355\u4e00\u6587\u4ef6\u4e2d\uff0c\u5177\u6709\u96f6\u914d\u7f6e\u3001\u8de8\u5e73\u53f0\u3001\u5360\u7528\u8d44\u6e90\u5c11\u7b49\u7279\u70b9\uff0c\u975e\u5e38\u9002\u5408\u4e2d\u5c0f\u578b\u5e94\u7528\u573a\u666f\u3002\u5728\u672c\u9879\u76ee\u4e2d\uff0cDjango\u9ed8\u8ba4\u4f7f\u7528SQLite\u4f5c\u4e3a\u5f00\u53d1\u6570\u636e\u5e93\uff0c\u5b58\u50a8\u7528\u6237\u4fe1\u606f\u3001\u8054\u7cfb\u8868\u5355\u6570\u636e\u7b49\u4e1a\u52a1\u6570\u636e\uff0c\u6ee1\u8db3\u4e86\u9879\u76ee\u7684\u9700\u6c42\u3002')
bp()
print('Section 2 done')


