bt('\u7cfb\u7edf\u91c7\u7528SQLite\u4f5c\u4e3a\u6570\u636e\u5e93\uff0c\u4e3b\u8981\u5305\u542b\u7528\u6237\u6570\u636e\u548c\u8054\u7cfb\u8868\u5355\u6570\u636e\u3002\u524d\u7aef\u7528\u6237\u8ba4\u8bc1\u6570\u636e\u5b58\u50a8\u5728\u6d4f\u89c8\u5668\u7684localStorage\u4e2d\u3002\u540e\u7aef\u6570\u636e\u5e93\u4e2d\uff0cShuju\u6570\u636e\u6a21\u578b\u7528\u4e8e\u5b58\u50a8\u8054\u7cfb\u8868\u5355\u7684\u63d0\u4ea4\u6570\u636e\uff0c\u5305\u542b\u8054\u7cfb\u4eba\u3001\u8054\u7cfb\u7535\u8bdd\u3001\u7535\u5b50\u90ae\u7bb1\u3001\u8981\u6c42\u8bf4\u660e\u548c\u521b\u5efa\u65f6\u95f4\u7b49\u5b57\u6bb5\uff0c\u6620\u5c04\u5230shuju\u6570\u636e\u5e93\u8868\u3002')

doc.add_heading('3.4 \u524d\u7aefUI\u8bbe\u8ba1', level=2)
bt('\u7cfb\u7edf\u91c7\u7528\u6df1\u8272\u4e3b\u9898\uff08Dark Mode\uff09\u4f5c\u4e3a\u6574\u4f53\u89c6\u89c9\u57fa\u8c03\uff0c\u4ee5\u6df1\u7070\u8272\u5c42\u7ea7\u4f5c\u4e3a\u80cc\u666f\u8272\uff0c\u7d2b\u8272\u7cfb\u4f5c\u4e3a\u5f3a\u8c03\u8272\uff0c\u8425\u9020\u51fa\u79d1\u6280\u611f\u4e0e\u827a\u672f\u611f\u517c\u5177\u7684\u89c6\u89c9\u98ce\u683c\u3002\u9875\u9762\u5185\u5bb9\u6700\u5927\u5bbd\u5ea6\u4e3a1700px\uff0c\u7ec4\u4ef6\u5706\u89d2\u7edf\u4e00\u4e3a\u4e09\u7ea7\u5c3a\u5ea6\u3002\u52a8\u753b\u65b9\u9762\u5927\u91cf\u8fd0\u7528GSAP ScrollTrigger\u5b9e\u73b0\u6eda\u52a8\u9a71\u52a8\u7684\u5165\u573a\u52a8\u753b\uff0c\u914d\u5408MagicBento\u7ec4\u4ef6\u7684\u503e\u659c\u3001\u78c1\u5438\u7b49\u5fae\u4ea4\u4e92\uff0c\u63d0\u5347\u6d4f\u89c8\u6c89\u6d78\u611f\u3002')
